SELECT 
  (SELECT COUNT(*) FROM superhero s JOIN colour c ON s.eye_colour_id = c.id WHERE s.weight_kg IS NULL AND c.colour = 'Blue') -
  (SELECT COUNT(*) FROM superhero s WHERE s.weight_kg IS NULL AND s.eye_colour_id IS NULL) AS difference;

